import React, { useState } from "react";
import { getPlayerStats } from "../api/apiService";

function PlayerComparison() {
  const [p1, setP1] = useState("");
  const [p2, setP2] = useState("");
  const [d1, setD1] = useState(null);
  const [d2, setD2] = useState(null);

  const compare = async () => {
    setD1(await getPlayerStats(p1));
    setD2(await getPlayerStats(p2));
  };

  return (
    <div>
      <h2>⚔ Player Comparison</h2>

      <input onChange={(e) => setP1(e.target.value)} placeholder="Player 1" />
      <input onChange={(e) => setP2(e.target.value)} placeholder="Player 2" />
      <button onClick={compare}>Compare</button>

      <div style={{ display: "flex", gap: "20px" }}>
        {d1 && <div className="card">{d1.name} - {d1.runs}</div>}
        {d2 && <div className="card">{d2.name} - {d2.runs}</div>}
      </div>
    </div>
  );
}

export default PlayerComparison;
